import{_ as e,o as r,c as o,a2 as a}from"./chunks/framework.CQMe4Urg.js";const m=JSON.parse('{"title":"第 12 章 MCP 协议","description":"","frontmatter":{},"headers":[],"relativePath":"12-mcp/index.md","filePath":"12-mcp/index.md","lastUpdated":1776333512000}'),n={name:"12-mcp/index.md"};function l(d,t,i,c,h,s){return r(),o("div",null,[...t[0]||(t[0]=[a('<h1 id="第-12-章-mcp-协议" tabindex="-1">第 12 章 MCP 协议 <a class="header-anchor" href="#第-12-章-mcp-协议" aria-label="Permalink to &quot;第 12 章 MCP 协议&quot;">​</a></h1><p>2024 年底，Anthropic 发布了 <strong>MCP（Model Context Protocol）</strong>——一个为 AI Agent 与外部工具和数据源之间建立统一连接标准的开放协议。你可以把它理解为 AI 领域的 USB-C：不管你用什么 Agent 框架，不管工具的内部实现是什么，只要双方都遵循 MCP 协议，就能即插即用。</p><p>在 MCP 之前，每个 Agent 框架都有自己的工具集成方式：LangChain 用 <code>@tool</code> 装饰器，OpenAI 用 Function Calling JSON Schema，每个 IDE 插件都要单独适配。开发者写一个 GitHub 工具，想在 Claude Desktop、Cursor、自建 Agent 中都能用，就得重写多次。这就是经典的 <strong>N x M 问题</strong>——N 个框架 x M 个工具 = N x M 个适配器。MCP 把它简化为 <strong>N + M</strong>。</p><p>这一章从 MCP 的核心概念开始，带你理解协议架构，然后亲手开发 MCP Server 和 Client，最后深入到安全实践和生产部署。</p><h2 id="本章内容" tabindex="-1">本章内容 <a class="header-anchor" href="#本章内容" aria-label="Permalink to &quot;本章内容&quot;">​</a></h2><table tabindex="0"><thead><tr><th>层级</th><th>内容</th><th>你将学到</th></tr></thead><tbody><tr><td><a href="./beginner.html">入门篇</a></td><td>MCP 解决什么问题、协议架构、三大核心能力</td><td>Host/Client/Server 三层架构，Tools/Resources/Prompts</td></tr><tr><td><a href="./intermediate.html">进阶篇</a></td><td>开发 MCP Server、开发 MCP Client、集成到 Agent</td><td>用 FastMCP 快速搭建 Server，将 MCP 工具桥接到 LLM</td></tr><tr><td><a href="./advanced.html">高级篇</a></td><td>生态与最佳实践、安全考虑、部署方案</td><td>权限最小化、输入验证、Docker 部署、多 Server 编排</td></tr></tbody></table><h2 id="参考资源" tabindex="-1">参考资源 <a class="header-anchor" href="#参考资源" aria-label="Permalink to &quot;参考资源&quot;">​</a></h2><ul><li><a href="https://modelcontextprotocol.io/" target="_blank" rel="noreferrer">Model Context Protocol 官方文档</a> -- 协议完整规范和教程</li><li><a href="https://github.com/modelcontextprotocol/python-sdk" target="_blank" rel="noreferrer">MCP Python SDK</a> -- Python 官方 SDK</li><li><a href="https://github.com/modelcontextprotocol/typescript-sdk" target="_blank" rel="noreferrer">MCP TypeScript SDK</a> -- TypeScript 官方 SDK</li><li><a href="https://www.anthropic.com/news/model-context-protocol" target="_blank" rel="noreferrer">Introducing the Model Context Protocol (Anthropic Blog)</a> -- MCP 发布博客</li><li><a href="https://github.com/punkpeye/awesome-mcp-servers" target="_blank" rel="noreferrer">awesome-mcp-servers</a> -- 社区 MCP Server 合集</li><li><a href="https://spec.modelcontextprotocol.io/" target="_blank" rel="noreferrer">MCP Specification</a> -- 协议技术规范</li></ul>',8)])])}const C=e(n,[["render",l]]);export{m as __pageData,C as default};
